void fft(double* x, double* y, long n, long sign) {
	long i, j, k, l, m, n1, n2;
	double c, c1, e, s, s1, t, tr, ti;
	for (j = i = 1; i < 31; i++) {
		m = i;
		j = 2 * j;
		if (j == n) break;
	}
	for (n1 = n - 1, j = 0, i = 0; i < n1; i++) {
		if (i < j) {
			tr = x[j];
			ti = y[j];
			x[j] = x[i];
			y[j] = y[i];
			x[i] = tr;
			y[i] = ti;
		}
		k = n / 2;
		while (k < (j + 1)) {
			j = j - k;
			k = k / 2;
		}
		j = j + k;
	}
	for (n1 = l = 1; l <= m; l++) {
		n1 = 2 * n1;
		n2 = n1 / 2;
		e = PI / n2;
		c = 1.0;
		s = 0.0;
		c1 = cos(e);
		s1 = -sign * sin(e);
		for (j = 0; j < n2; j++) {
			for (i = j; i < n; i += n1) {
				k = i + n2;
				tr = c * x[k] - s * y[k];
				ti = c * y[k] + s * x[k];
				x[k] = x[i] - tr;
				y[k] = y[i] - ti;
				x[i] = x[i] + tr;
				y[i] = y[i] + ti;
			}
			t = c;
			c = c * c1 - s * s1;
			s = t * s1 + s * c1;
		}
	}
	if (sign == -1) {
		for (i = 0; i < n; i++) {
			x[i] /= n;
			y[i] /= n;
		}
	}
}



void compute_snr(const char* filename, double* mel_spectrogram, int signal_length) {
	FILE* file = fopen(filename, "r");
	if (file == NULL) {
		fprintf(stderr, "Error opening file %s\n", filename);
		return;
	}
	double* signal = (double*)malloc(signal_length * sizeof(double));
	if (signal == NULL) {
		fprintf(stderr, "Memory allocation failed for signal array\n");
		fclose(file);
		return;
	}
	double noise = 0.0;
	double noisepower = 0.0;
	double signalpower = 0.0;
	for (int i = 0; i < signal_length; i++) {
		if (fscanf(file, "%lf", &signal[i]) != 1) {
			/*printf("%d\n", i);
			fprintf(stderr, "Error reading data from file\n");*/
			break;
		}
		signalpower += mel_spectrogram[i] * mel_spectrogram[i];
		noise = signal[i] - mel_spectrogram[i];
		noisepower += noise * noise;
	}
	if (signalpower > 0) {
		double snr = 10.0 * log10(signalpower / noisepower);
		printf("SNR: %lf dB\n", snr);
	}
	else {
		printf("Error: Signal power is zero, cannot compute SNR.\n");
	}
	free(signal);
	fclose(file);
}


void initialize(void)
{
	int i, j, n;
	double all_freqs[FREQ_NUM], m_pts[MELS_NUM + 2], f_pts[MELS_NUM + 2], f_diff[MELS_NUM + 1], slopes[MELS_NUM + 2];

	for (n = 0; n < WIN_SIZE; n++) window[n] = 0.5f * (1.0f - cos(2.0f * PI * n / (WIN_SIZE)));

	//Mycreate_fb_matrix(FREQ_NUM, 0.0, FS / 2.0, FS);
	mel_filter_bank = (double*)malloc(FREQ_NUM * MELS_NUM * sizeof(double));
	for (int i = 0; i < FREQ_NUM; i++) all_freqs[i] = (double)i * (FS / 2.0f) / (FREQ_NUM - 1);

	double m_min = 2595.0f * log10(1.0f + (0 / 700.0f));
	double m_max = 2595.0f * log10(1.0f + (FS / 2.0f / 700.0f));

	for (m_pts[0] = f_pts[0] = 0, i = 0; i < MELS_NUM + 1; i++)
	{
		m_pts[i + 1] = m_min + (m_max - m_min) * (i + 1) / (MELS_NUM + 1);
		f_pts[i + 1] = 700.0f * (pow(10, m_pts[i + 1] / 2595.0f) - 1.0f);
		f_diff[i] = f_pts[i + 1] - f_pts[i];
	}
	for (i = 0; i < FREQ_NUM; i++)
	{
		for (j = 0; j < MELS_NUM + 2; j++) slopes[j] = f_pts[j] - all_freqs[i];
		for (j = 0; j < MELS_NUM; j++) mel_filter_bank[i*MELS_NUM + j] = fmax(0.0, fmin(-slopes[j] / f_diff[j], slopes[j + 2] / f_diff[j + 1]));
	}
}